import sys, json

data = json.load(sys.stdin)
json.dump(data, open('after-cpm-packages.json', 'w'), indent=2)

# Compare baseline vs after
baseline = json.load(open('baseline-packages.json'))
after = data

def get_pkg_map(projects):
    result = {}
    for proj in projects:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_pkg_map(baseline['projects'])
a = get_pkg_map(after['projects'])

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    proj, fw, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((proj, fw, pkg, bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((proj, fw, pkg, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')
else:
    print('  None - fully version-neutral!')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}): {u[2]} = {u[3]}')
"

